import React, { useState } from "react";
import styles from "./nav-bar.module.css";
import NavButton from "../nav-button";
import MegaMenu from "../mega-menu";

const NavBar: React.FC = () => {
  const [isDiscoveryMenuVisible, setIsDiscoveryMenuVisible] = useState<boolean>(false);
  const [isAboutMenuVisible, setIsAboutMenuVisible] = useState<boolean>(false);

  // Function to toggle Discovery MegaMenu visibility
  const toggleDiscoveryMenu = () => {
    setIsDiscoveryMenuVisible(!isDiscoveryMenuVisible);
  };

  // Function to toggle About MegaMenu visibility
  const toggleAboutMenu = () => {
    setIsAboutMenuVisible(!isAboutMenuVisible);
  };

  return (
    <>
      <div className={styles.nav__bar}>
        <NavButton text="Discovery" handleClick={toggleDiscoveryMenu} />
        <NavButton text="About" handleClick={toggleAboutMenu} />
        <NavButton text="Contact us" href="/contact" isLink={true} />
      </div>
      <MegaMenu show={isDiscoveryMenuVisible || isAboutMenuVisible} />
    </>
  );
};

export default NavBar;


